const amount = Number(body.amount || 0);
const transferAt = body.transferAt || '';
const note = String(body.note || '').trim();
const proofDataUrl = String(body.proofDataUrl || '');
if (!uid || !orderId || !Number.isFinite(amount) || amount <= 0 || !transferAt || !proofDataUrl) throw new Error('Missing payment proof fields');
