if (!order) throw new Error('Order not found or does not belong to this user');
if (String(order.Status || '').toLowerCase() !== 'approved') throw new Error('Only approved orders can submit payment proof');
const currentPayment = String(order.Payment_Status || '').toLowerCase();
if (['submitted', 'verified', 'paid'].includes(currentPayment)) throw new Error('Payment proof was already submitted for this order');
const match = proofDataUrl.match(/^data:(image\/(?:jpeg|png|webp));base64,([A-Za-z0-9+/=]+)$/);
if (!match) throw new Error('Only JPG, PNG, or WEBP proof images are accepted');
const bytes = Math.floor(match[2].length * 0.75);
if (bytes > 5 * 1024 * 1024) throw new Error('Proof image must be 5 MB or smaller');
const ext = match[1] === 'image/png' ? 'png' : match[1] === 'image/webp' ? 'webp' : 'jpg';
const safeName = 'PAYMENT_' + orderId.replace(/[^A-Za-z0-9_-]/g, '_') + '_' + Date.now() + '.' + ext;
return [{ json: { orderId, lineUid: uid, amount, transferAt, note, submittedAt: new Date().toISOString(), proofFileName: safeName }, binary: { data: { data: match[2], mimeType: match[1], fileName: safeName, fileExtension: ext } } }];

